Index: backend/internal/platform/auth/token.go
===================================================================
--- backend/internal/platform/auth/token.go	
+++ backend/internal/platform/auth/token.go	
@@ -0,0 +1,79 @@
+package auth
+
+import (
+	"crypto/hmac"
+	"crypto/sha256"
+	"encoding/base64"
+	"encoding/json"
+	"errors"
+	"strings"
+	"time"
+)
+
+type Claims struct {
+	UserID string `json:"uid"`
+	Exp    int64  `json:"exp"`
+}
+
+type TokenManager struct {
+	secret []byte
+	ttl    time.Duration
+}
+
+func NewTokenManager(secret string, ttl time.Duration) *TokenManager {
+	return &TokenManager{secret: []byte(secret), ttl: ttl}
+}
+
+func (t *TokenManager) MakeToken(userID string) (string, time.Time, error) {
+	expiresAt := time.Now().UTC().Add(t.ttl)
+	claims := Claims{UserID: userID, Exp: expiresAt.Unix()}
+
+	payload, err := json.Marshal(claims)
+	if err != nil {
+		return "", time.Time{}, err
+	}
+	payload64 := base64.RawURLEncoding.EncodeToString(payload)
+	mac := hmac.New(sha256.New, t.secret)
+	if _, err := mac.Write([]byte(payload64)); err != nil {
+		return "", time.Time{}, err
+	}
+	sig := base64.RawURLEncoding.EncodeToString(mac.Sum(nil))
+	return payload64 + "." + sig, expiresAt, nil
+}
+
+func (t *TokenManager) ParseToken(token string) (Claims, error) {
+	parts := strings.Split(token, ".")
+	if len(parts) != 2 {
+		return Claims{}, errors.New("invalid token format")
+	}
+
+	mac := hmac.New(sha256.New, t.secret)
+	if _, err := mac.Write([]byte(parts[0])); err != nil {
+		return Claims{}, err
+	}
+	expected := mac.Sum(nil)
+	actual, err := base64.RawURLEncoding.DecodeString(parts[1])
+	if err != nil {
+		return Claims{}, err
+	}
+	if !hmac.Equal(expected, actual) {
+		return Claims{}, errors.New("token signature mismatch")
+	}
+
+	payload, err := base64.RawURLEncoding.DecodeString(parts[0])
+	if err != nil {
+		return Claims{}, err
+	}
+
+	var claims Claims
+	if err := json.Unmarshal(payload, &claims); err != nil {
+		return Claims{}, err
+	}
+	if claims.UserID == "" || claims.Exp == 0 {
+		return Claims{}, errors.New("invalid token claims")
+	}
+	if time.Now().UTC().Unix() > claims.Exp {
+		return Claims{}, errors.New("token expired")
+	}
+	return claims, nil
+}

Index: backend/internal/services/auth_service.go
===================================================================
--- backend/internal/services/auth_service.go	
+++ backend/internal/services/auth_service.go	
@@ -0,0 +1,115 @@
+package services
+
+import (
+	"context"
+	"database/sql"
+	"errors"
+	"strings"
+
+	"golang.org/x/crypto/bcrypt"
+
+	"pantrypal/backend/internal/platform/auth"
+	"pantrypal/backend/internal/repositories"
+	"pantrypal/backend/internal/transport/http/dto"
+)
+
+var (
+	ErrInvalidEmail       = errors.New("email is invalid")
+	ErrWeakPassword       = errors.New("password must be at least 8 characters")
+	ErrEmailConflict      = errors.New("email already registered")
+	ErrInvalidCredentials = errors.New("invalid credentials")
+)
+
+type AuthService struct {
+	users  *repositories.UserRepository
+	tokens *auth.TokenManager
+}
+
+func NewAuthService(users *repositories.UserRepository, tokens *auth.TokenManager) *AuthService {
+	return &AuthService{users: users, tokens: tokens}
+}
+
+func (s *AuthService) Register(ctx context.Context, req dto.RegisterRequest) (dto.AuthResponse, error) {
+	req.Email = strings.ToLower(strings.TrimSpace(req.Email))
+	req.DisplayName = strings.TrimSpace(req.DisplayName)
+	if !strings.Contains(req.Email, "@") {
+		return dto.AuthResponse{}, ErrInvalidEmail
+	}
+	if len(req.Password) < 8 {
+		return dto.AuthResponse{}, ErrWeakPassword
+	}
+
+	exists, err := s.users.ExistsByEmail(ctx, req.Email)
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+	if exists {
+		return dto.AuthResponse{}, ErrEmailConflict
+	}
+
+	hash, err := bcrypt.GenerateFromPassword([]byte(req.Password), bcrypt.DefaultCost)
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+
+	user, err := s.users.CreateUser(ctx, req.Email, string(hash), req.DisplayName)
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+
+	token, expiresAt, err := s.tokens.MakeToken(user.ID)
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+
+	return dto.AuthResponse{
+		Token:     token,
+		ExpiresAt: expiresAt.Format("2006-01-02T15:04:05Z07:00"),
+		User: dto.UserResponse{
+			ID:          user.ID,
+			Email:       user.Email,
+			DisplayName: user.DisplayName,
+		},
+	}, nil
+}
+
+func (s *AuthService) Login(ctx context.Context, req dto.LoginRequest) (dto.AuthResponse, error) {
+	req.Email = strings.ToLower(strings.TrimSpace(req.Email))
+	user, err := s.users.GetByEmail(ctx, req.Email)
+	if errors.Is(err, sql.ErrNoRows) {
+		return dto.AuthResponse{}, ErrInvalidCredentials
+	}
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+	if bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(req.Password)) != nil {
+		return dto.AuthResponse{}, ErrInvalidCredentials
+	}
+
+	if err := s.users.EnsureDefaultProfileRows(ctx, user.ID); err != nil {
+		return dto.AuthResponse{}, err
+	}
+
+	token, expiresAt, err := s.tokens.MakeToken(user.ID)
+	if err != nil {
+		return dto.AuthResponse{}, err
+	}
+
+	return dto.AuthResponse{
+		Token:     token,
+		ExpiresAt: expiresAt.Format("2006-01-02T15:04:05Z07:00"),
+		User: dto.UserResponse{
+			ID:          user.ID,
+			Email:       user.Email,
+			DisplayName: user.DisplayName,
+		},
+	}, nil
+}
+
+func (s *AuthService) Me(ctx context.Context, userID string) (dto.UserResponse, error) {
+	user, err := s.users.GetByID(ctx, userID)
+	if err != nil {
+		return dto.UserResponse{}, err
+	}
+	return dto.UserResponse{ID: user.ID, Email: user.Email, DisplayName: user.DisplayName}, nil
+}

Index: backend/internal/services/profile_service.go
===================================================================
--- backend/internal/services/profile_service.go	
+++ backend/internal/services/profile_service.go	
@@ -0,0 +1,47 @@
+package services
+
+import (
+	"context"
+	"errors"
+
+	"pantrypal/backend/internal/repositories"
+	"pantrypal/backend/internal/transport/http/dto"
+)
+
+var ErrInvalidBudget = errors.New("amountCents is required and must be >= 0")
+
+type ProfileService struct {
+	users *repositories.UserRepository
+}
+
+func NewProfileService(users *repositories.UserRepository) *ProfileService {
+	return &ProfileService{users: users}
+}
+
+func (s *ProfileService) GetProfile(ctx context.Context, userID string) (dto.ProfileResponse, error) {
+	return s.users.GetProfile(ctx, userID)
+}
+
+func (s *ProfileService) PatchMetrics(ctx context.Context, userID string, req dto.PatchMetricsRequest) (dto.ProfileResponse, error) {
+	if err := s.users.UpsertMetrics(ctx, userID, req); err != nil {
+		return dto.ProfileResponse{}, err
+	}
+	return s.users.GetProfile(ctx, userID)
+}
+
+func (s *ProfileService) PatchPreferences(ctx context.Context, userID string, req dto.PatchPreferencesRequest) (dto.ProfileResponse, error) {
+	if err := s.users.UpsertPreferences(ctx, userID, req); err != nil {
+		return dto.ProfileResponse{}, err
+	}
+	return s.users.GetProfile(ctx, userID)
+}
+
+func (s *ProfileService) PatchBudget(ctx context.Context, userID string, req dto.PatchBudgetRequest) (dto.ProfileResponse, error) {
+	if req.AmountCents == nil || *req.AmountCents < 0 {
+		return dto.ProfileResponse{}, ErrInvalidBudget
+	}
+	if err := s.users.UpsertBudget(ctx, userID, req); err != nil {
+		return dto.ProfileResponse{}, err
+	}
+	return s.users.GetProfile(ctx, userID)
+}

Index: backend/internal/transport/http/handlers/auth_handler.go
===================================================================
--- backend/internal/transport/http/handlers/auth_handler.go	
+++ backend/internal/transport/http/handlers/auth_handler.go	
@@ -0,0 +1,83 @@
+package handlers
+
+import (
+	"database/sql"
+	"errors"
+	"net/http"
+
+	"pantrypal/backend/internal/services"
+	"pantrypal/backend/internal/transport/http/dto"
+	"pantrypal/backend/internal/transport/http/middleware"
+)
+
+type AuthHandler struct {
+	auth *services.AuthService
+}
+
+func NewAuthHandler(auth *services.AuthService) *AuthHandler {
+	return &AuthHandler{auth: auth}
+}
+
+func (h *AuthHandler) Register(w http.ResponseWriter, r *http.Request) {
+	var req dto.RegisterRequest
+	if err := ReadJSON(r, &req); err != nil {
+		WriteAPIError(w, http.StatusBadRequest, "bad_request", "invalid JSON payload")
+		return
+	}
+
+	res, err := h.auth.Register(r.Context(), req)
+	if err != nil {
+		switch {
+		case errors.Is(err, services.ErrInvalidEmail), errors.Is(err, services.ErrWeakPassword):
+			WriteAPIError(w, http.StatusBadRequest, "validation_error", err.Error())
+		case errors.Is(err, services.ErrEmailConflict):
+			WriteAPIError(w, http.StatusConflict, "conflict", err.Error())
+		default:
+			WriteAPIError(w, http.StatusInternalServerError, "internal_error", "failed to register user")
+		}
+		return
+	}
+
+	WriteJSON(w, http.StatusCreated, res)
+}
+
+func (h *AuthHandler) Login(w http.ResponseWriter, r *http.Request) {
+	var req dto.LoginRequest
+	if err := ReadJSON(r, &req); err != nil {
+		WriteAPIError(w, http.StatusBadRequest, "bad_request", "invalid JSON payload")
+		return
+	}
+
+	res, err := h.auth.Login(r.Context(), req)
+	if err != nil {
+		switch {
+		case errors.Is(err, services.ErrInvalidCredentials):
+			WriteAPIError(w, http.StatusUnauthorized, "unauthorized", err.Error())
+		default:
+			WriteAPIError(w, http.StatusInternalServerError, "internal_error", "failed to login")
+		}
+		return
+	}
+
+	WriteJSON(w, http.StatusOK, res)
+}
+
+func (h *AuthHandler) Me(w http.ResponseWriter, r *http.Request) {
+	userID, ok := middleware.UserIDFromContext(r.Context())
+	if !ok {
+		WriteAPIError(w, http.StatusUnauthorized, "unauthorized", "missing auth context")
+		return
+	}
+
+	me, err := h.auth.Me(r.Context(), userID)
+	if err != nil {
+		if errors.Is(err, sql.ErrNoRows) {
+			WriteAPIError(w, http.StatusUnauthorized, "unauthorized", "user not found")
+			return
+		}
+		WriteAPIError(w, http.StatusInternalServerError, "internal_error", "failed to load current user")
+		return
+	}
+
+	WriteJSON(w, http.StatusOK, map[string]dto.UserResponse{"user": me})
+}

