package repositories

import (
	"context"
	"database/sql"
	"time"

	"pantrypal/backend/internal/platform/id"
	"pantrypal/backend/internal/transport/http/dto"
)

type ChatRepository struct {
	db *sql.DB
}

func NewChatRepository(db *sql.DB) *ChatRepository {
	return &ChatRepository{db: db}
}

type StoredChatMessage struct {
	ID        string
	UserID    string
	Role      string
	Action    string
	Content   string
	CreatedAt string
}

func (r *ChatRepository) InsertUserMessage(ctx context.Context, userID, message, action string) (StoredChatMessage, error) {
	msgID, err := id.New("msg")
	if err != nil {
		return StoredChatMessage{}, err
	}

	now := time.Now().UTC().Format(time.RFC3339)

	_, err = r.db.ExecContext(
		ctx,
		`INSERT INTO chat_messages (id, user_id, role, action, content, metadata_json, created_at)
		 VALUES (?, ?, 'user', NULLIF(?, ''), ?, '{}', ?)`,
		msgID,
		userID,
		action,
		message,
		now,
	)
	if err != nil {
		return StoredChatMessage{}, err
	}

	return StoredChatMessage{
		ID:        msgID,
		UserID:    userID,
		Role:      "user",
		Action:    action,
		Content:   message,
		CreatedAt: now,
	}, nil
}

func (r *ChatRepository) ListRecent(ctx context.Context, userID string, limit int) ([]StoredChatMessage, error) {
	if limit <= 0 || limit > 100 {
		limit = 50
	}

	rows, err := r.db.QueryContext(
		ctx,
		`SELECT id, user_id, role, COALESCE(action, ''), content, created_at
		 FROM chat_messages
		 WHERE user_id = ?
		 ORDER BY created_at DESC
		 LIMIT ?`,
		userID,
		limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	messages := make([]StoredChatMessage, 0, limit)
	for rows.Next() {
		var msg StoredChatMessage
		if err := rows.Scan(&msg.ID, &msg.UserID, &msg.Role, &msg.Action, &msg.Content, &msg.CreatedAt); err != nil {
			return nil, err
		}
		messages = append(messages, msg)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}

	for i, j := 0, len(messages)-1; i < j; i, j = i+1, j-1 {
		messages[i], messages[j] = messages[j], messages[i]
	}

	return messages, nil
}

package services

import (
	"context"

	"pantrypal/backend/internal/repositories"
	"pantrypal/backend/internal/transport/http/dto"
)

type ChatService struct {
	chat *repositories.ChatRepository
}

func NewChatService(chat *repositories.ChatRepository) *ChatService {
	return &ChatService{chat: chat}
}

func (s *ChatService) SendMessage(ctx context.Context, userID string, req dto.ChatSendRequest) (dto.ChatMessageResponse, error) {
	msg, err := s.chat.InsertUserMessage(ctx, userID, req.Message, req.Action)
	if err != nil {
		return dto.ChatMessageResponse{}, err
	}
	return dto.ChatMessageResponse{
		ID:        msg.ID,
		Role:      msg.Role,
		Action:    msg.Action,
		Content:   msg.Content,
		CreatedAt: msg.CreatedAt,
	}, nil
}

func (s *ChatService) GetHistory(ctx context.Context, userID string, limit int) (dto.ChatHistoryResponse, error) {
	messages, err := s.chat.ListRecent(ctx, userID, limit)
	if err != nil {
		return dto.ChatHistoryResponse{}, err
	}
	out := make([]dto.ChatMessageResponse, 0, len(messages))
	for _, msg := range messages {
		out = append(out, dto.ChatMessageResponse{
			ID:        msg.ID,
			Role:      msg.Role,
			Action:    msg.Action,
			Content:   msg.Content,
			CreatedAt: msg.CreatedAt,
		})
	}
	return dto.ChatHistoryResponse{Messages: out}, nil
}

package handlers

import (
	"net/http"
	"strconv"

	"pantrypal/backend/internal/services"
	"pantrypal/backend/internal/transport/http/dto"
	"pantrypal/backend/internal/transport/http/middleware"
)

type ChatHandler struct {
	chat *services.ChatService
}

func NewChatHandler(chat *services.ChatService) *ChatHandler {
	return &ChatHandler{chat: chat}
}

func (h *ChatHandler) SendMessage(w http.ResponseWriter, r *http.Request) {
	userID, ok := middleware.UserIDFromContext(r.Context())
	if !ok {
		WriteAPIError(w, http.StatusUnauthorized, "unauthorized", "missing auth context")
		return
	}

	var req dto.ChatSendRequest
	if err := ReadJSON(r, &req); err != nil {
		WriteAPIError(w, http.StatusBadRequest, "bad_request", "invalid JSON payload")
		return
	}
	if req.Message == "" {
		WriteAPIError(w, http.StatusBadRequest, "validation_error", "message is required")
		return
	}

	res, err := h.chat.SendMessage(r.Context(), userID, req)
	if err != nil {
		WriteAPIError(w, http.StatusInternalServerError, "internal_error", "failed to send message")
		return
	}

	WriteJSON(w, http.StatusCreated, res)
}

func (h *ChatHandler) GetHistory(w http.ResponseWriter, r *http.Request) {
	userID, ok := middleware.UserIDFromContext(r.Context())
	if !ok {
		WriteAPIError(w, http.StatusUnauthorized, "unauthorized", "missing auth context")
		return
	}

	limit := 50
	if l := r.URL.Query().Get("limit"); l != "" {
		if parsed, err := strconv.Atoi(l); err == nil && parsed > 0 {
			limit = parsed
		}
	}

	res, err := h.chat.GetHistory(r.Context(), userID, limit)
	if err != nil {
		WriteAPIError(w, http.StatusInternalServerError, "internal_error", "failed to load chat history")
		return
	}

	WriteJSON(w, http.StatusOK, res)
}

